import { useState, useEffect, useRef } from 'react';
import * as LWC from 'lightweight-charts';
const { createChart, CrosshairMode, CandlestickSeries, LineSeries } = LWC;
import { api } from '../utils/api';

const C = {
  bg: '#0B0F14', surface: '#0F1620', surface2: '#111A24',
  border: '#1F2A37', text: '#E5E7DB', muted: '#90A3AF',
  green: '#22C55E', red: '#EF4444', blue: '#60A5FA',
  amber: '#F59E0B', purple: '#A78BFA', cyan: '#06B6D4',
};
const mono = "'JetBrains Mono', monospace";

const INDICATORS = [
  { id: 'sma', label: 'SMA', defaultPeriod: 20, color: C.blue, overlay: true },
  { id: 'ema', label: 'EMA', defaultPeriod: 12, color: C.purple, overlay: true },
  { id: 'bollinger', label: 'Bollinger Bands', defaultPeriod: 20, color: C.amber, overlay: true },
  { id: 'vwap', label: 'VWAP', defaultPeriod: 1, color: '#06B6D4', overlay: true },
  { id: 'rsi', label: 'RSI', defaultPeriod: 14, color: C.blue, overlay: false },
  { id: 'macd', label: 'MACD', defaultPeriod: 12, color: C.green, overlay: false },
  { id: 'atr', label: 'ATR', defaultPeriod: 14, color: C.amber, overlay: false },
  { id: 'stochastic', label: 'Stochastic', defaultPeriod: 14, color: C.purple, overlay: false },
  { id: 'obv', label: 'OBV', defaultPeriod: 1, color: '#06B6D4', overlay: false },
  { id: 'adx', label: 'ADX', defaultPeriod: 14, color: C.red, overlay: false },
  { id: 'cci', label: 'CCI', defaultPeriod: 20, color: C.amber, overlay: false },
  { id: 'williamsR', label: 'Williams %R', defaultPeriod: 14, color: C.purple, overlay: false },
  { id: 'supertrend', label: 'Supertrend', defaultPeriod: 10, color: C.green, overlay: true },
  { id: 'keltner', label: 'Keltner Channel', defaultPeriod: 20, color: C.red, overlay: true },
  { id: 'donchian', label: 'Donchian Channel', defaultPeriod: 20, color: '#06B6D4', overlay: true },
  { id: 'parabolicSar', label: 'Parabolic SAR', defaultPeriod: 1, color: C.amber, overlay: true },
  { id: 'ichimoku', label: 'Ichimoku Cloud', defaultPeriod: 26, color: C.purple, overlay: true },
];

function computeSMA(data, period) {
  const result = [];
  for (let i = period - 1; i < data.length; i++) {
    let sum = 0;
    for (let j = 0; j < period; j++) sum += data[i - j].close;
    result.push({ time: data[i].time, value: sum / period });
  }
  return result;
}

function computeEMA(data, period) {
  const result = [];
  const k = 2 / (period + 1);
  let prev = data.slice(0, period).reduce((s, d) => s + d.close, 0) / period;
  result.push({ time: data[period - 1].time, value: prev });
  for (let i = period; i < data.length; i++) {
    prev = data[i].close * k + prev * (1 - k);
    result.push({ time: data[i].time, value: prev });
  }
  return result;
}

function computeRSI(data, period) {
  if (data.length < period + 2) return [];
  const result = [];
  let gains = 0, losses = 0;
  for (let i = 1; i <= period; i++) {
    const d = data[i].close - data[i - 1].close;
    if (d > 0) gains += d; else losses -= d;
  }
  let avgGain = gains / period, avgLoss = losses / period;
  const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
  result.push({ time: data[period].time, value: 100 - 100 / (1 + rs) });
  for (let i = period + 1; i < data.length; i++) {
    const d = data[i].close - data[i - 1].close;
    avgGain = (avgGain * (period - 1) + (d > 0 ? d : 0)) / period;
    avgLoss = (avgLoss * (period - 1) + (d < 0 ? -d : 0)) / period;
    const r = avgLoss === 0 ? 100 : avgGain / avgLoss;
    result.push({ time: data[i].time, value: 100 - 100 / (1 + r) });
  }
  return result;
}

function computeBollinger(data, period) {
  const upper = [], lower = [], mid = [];
  for (let i = period - 1; i < data.length; i++) {
    let sum = 0;
    for (let j = 0; j < period; j++) sum += data[i - j].close;
    const avg = sum / period;
    let sqSum = 0;
    for (let j = 0; j < period; j++) sqSum += Math.pow(data[i - j].close - avg, 2);
    const std = Math.sqrt(sqSum / period);
    mid.push({ time: data[i].time, value: avg });
    upper.push({ time: data[i].time, value: avg + 2 * std });
    lower.push({ time: data[i].time, value: avg - 2 * std });
  }
  return { upper, lower, mid };
}

export default function AdvancedChartingModule({ symbol: propSymbol }) {
  const [symbol, setSymbol] = useState(propSymbol || 'AAPL');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeIndicators, setActiveIndicators] = useState({});
  const [ohlcvData, setOhlcvData] = useState([]);
  const chartContainerRef = useRef(null);
  const chartRef = useRef(null);
  const seriesRef = useRef({});

  useEffect(() => {
    api(`/charts/ohlcv/${symbol}?timeframe=1D`)
      .then(data => {
        if (data?.bars) setOhlcvData(data.bars.map(b => ({
          time: b.date || b.time, open: b.open, high: b.high, low: b.low, close: b.close, volume: b.volume,
        })));
      })
      .catch(() => {});
  }, [symbol]);

  useEffect(() => {
    if (!chartContainerRef.current || !ohlcvData.length) return;
    if (chartRef.current) chartRef.current.remove();
    const chart = createChart(chartContainerRef.current, {
      width: chartContainerRef.current.clientWidth,
      height: 500,
      layout: { background: { color: C.bg }, textColor: C.muted, fontFamily: mono, fontSize: 11 },
      grid: { vertLines: { color: C.border }, horzLines: { color: C.border } },
      crosshair: { mode: CrosshairMode.Normal },
      rightPriceScale: { borderColor: C.border },
      timeScale: { borderColor: C.border },
    });
    const cs = chart.addSeries(CandlestickSeries, {
      upColor: C.green, downColor: C.red, borderUpColor: C.green, borderDownColor: C.red,
      wickUpColor: C.green, wickDownColor: C.red,
    });
    cs.setData(ohlcvData);
    chartRef.current = chart;
    seriesRef.current = { candles: cs };
    const ro = new ResizeObserver(() => {
      if (chartContainerRef.current) chart.applyOptions({ width: chartContainerRef.current.clientWidth });
    });
    ro.observe(chartContainerRef.current);
    return () => { ro.disconnect(); chart.remove(); };
  }, [ohlcvData]);

  useEffect(() => {
    if (!chartRef.current || !ohlcvData.length) return;
    const chart = chartRef.current;
    Object.keys(seriesRef.current).forEach(k => {
      if (k !== 'candles') { try { chart.removeSeries(seriesRef.current[k]); } catch {} delete seriesRef.current[k]; }
    });
    Object.entries(activeIndicators).forEach(([id, config]) => {
      if (!config.enabled) return;
      const ind = INDICATORS.find(i => i.id === id);
      if (!ind) return;
      const period = config.period || ind.defaultPeriod;
      const color = config.color || ind.color;
      if (id === 'sma') {
        const s = chart.addSeries(LineSeries, { color, lineWidth: 1, priceScaleId: 'right' });
        s.setData(computeSMA(ohlcvData, period)); seriesRef.current[id] = s;
      } else if (id === 'ema') {
        const s = chart.addSeries(LineSeries, { color, lineWidth: 1, priceScaleId: 'right' });
        s.setData(computeEMA(ohlcvData, period)); seriesRef.current[id] = s;
      } else if (id === 'rsi') {
        const d = computeRSI(ohlcvData, period);
        if (d.length) { const s = chart.addSeries(LineSeries, { color, lineWidth: 1 }); s.setData(d); seriesRef.current[id] = s; }
      } else if (id === 'bollinger') {
        const bb = computeBollinger(ohlcvData, period);
        const su = chart.addSeries(LineSeries, { color, lineWidth: 1, lineStyle: 2, priceScaleId: 'right' });
        su.setData(bb.upper); seriesRef.current[id + '_u'] = su;
        const sl = chart.addSeries(LineSeries, { color, lineWidth: 1, lineStyle: 2, priceScaleId: 'right' });
        sl.setData(bb.lower); seriesRef.current[id + '_l'] = sl;
        const sm = chart.addSeries(LineSeries, { color, lineWidth: 1, priceScaleId: 'right' });
        sm.setData(bb.mid); seriesRef.current[id + '_m'] = sm;
      }
    });
  }, [activeIndicators, ohlcvData]);

  const toggleIndicator = (id) => {
    setActiveIndicators(prev => {
      const cur = prev[id] || { enabled: false, period: INDICATORS.find(i => i.id === id)?.defaultPeriod };
      return { ...prev, [id]: { ...cur, enabled: !cur.enabled } };
    });
  };

  const updatePeriod = (id, period) => {
    setActiveIndicators(prev => ({ ...prev, [id]: { ...(prev[id] || {}), enabled: true, period: parseInt(period) || 14 } }));
  };

  const filtered = INDICATORS.filter(i => i.label.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div style={{ display: 'flex', gap: 16, padding: 24, background: C.bg, minHeight: '100vh', color: C.text, fontFamily: mono }}>
      <div style={{ flex: 1 }}>
        <div style={{ display: 'flex', gap: 8, marginBottom: 12, alignItems: 'center' }}>
          <input value={symbol} onChange={e => setSymbol(e.target.value.toUpperCase())} placeholder="Symbol"
            style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 6, padding: '8px 12px', color: C.text, fontFamily: mono, fontSize: 14, width: 120 }} />
          <div style={{ fontSize: 13, color: C.muted }}>{ohlcvData.length} bars</div>
        </div>
        <div ref={chartContainerRef} style={{ borderRadius: 10, overflow: 'hidden', border: `1px solid ${C.border}` }} />
      </div>
      <div style={{ width: 260, background: C.surface, border: `1px solid ${C.border}`, borderRadius: 14, padding: 16, overflowY: 'auto', maxHeight: 'calc(100vh - 80px)' }}>
        <h3 style={{ fontSize: 14, fontWeight: 700, marginBottom: 12 }}>Indicators</h3>
        <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Search..."
          style={{ width: '100%', background: C.bg, border: `1px solid ${C.border}`, borderRadius: 6, padding: '6px 10px', color: C.text, fontFamily: mono, fontSize: 11, marginBottom: 12 }} />
        {filtered.map(ind => {
          const active = activeIndicators[ind.id]?.enabled;
          return (
            <div key={ind.id} style={{ padding: '8px 10px', borderBottom: `1px solid ${C.border}`, opacity: active ? 1 : 0.6 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                  <div style={{ width: 10, height: 10, borderRadius: '50%', background: ind.color }} />
                  <span style={{ fontSize: 13, fontWeight: 600 }}>{ind.label}</span>
                </div>
                <button onClick={() => toggleIndicator(ind.id)} style={{ width: 36, height: 20, borderRadius: 10, border: 'none', background: active ? C.green : C.border, cursor: 'pointer', position: 'relative' }}>
                  <div style={{ width: 14, height: 14, borderRadius: '50%', background: '#fff', position: 'absolute', top: 3, left: active ? 19 : 3, transition: 'left 0.25s' }} />
                </button>
              </div>
              {active && (
                <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 8 }}>
                  <span style={{ fontSize: 10, color: C.muted }}>Period:</span>
                  <input type="number" value={activeIndicators[ind.id]?.period || ind.defaultPeriod} onChange={e => updatePeriod(ind.id, e.target.value)}
                    style={{ width: 50, background: C.bg, border: `1px solid ${C.border}`, borderRadius: 6, padding: '2px 6px', color: C.text, fontFamily: mono, fontSize: 11 }} />
                  <span style={{ fontSize: 10, padding: '1px 6px', borderRadius: 6, background: ind.overlay ? `${C.blue}22` : `${C.amber}22`, color: ind.overlay ? C.blue : C.amber }}>
                    {ind.overlay ? 'overlay' : 'pane'}
                  </span>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}
